import React, { useState } from 'react';
import { useData } from '../../context/DataContext';

const SchedulerTaskManager = () => {
  const { tasks, addTask, deleteTask, staffList, schedules, addSchedule, deleteSchedule } = useData();
  
  // 1. STATE CHO NHIỆM VỤ ĐƠN
  const [newTask, setNewTask] = useState({ 
      title: '', assigneeId: '', description: '',
      startTime: '', endTime: '', 
      assignedRole: 'ST'
  });

  // 2. STATE CHO LỊCH CÔNG TÁC (ĐỊNH KỲ)
  const [scheduleConfig, setScheduleConfig] = useState({
      title: '', assigneeId: '', description: '',
      startTimeStr: '', endTimeStr: '', // Lưu dưới dạng HH:mm
      assignedRole: 'ST',
      repeatWeeks: 1,
      days: [] // ['Mon', 'Tue'...]
  });

  const daysOfWeek = [
      { key: 'Mon', label: 'T2' }, { key: 'Tue', label: 'T3' }, { key: 'Wed', label: 'T4' },
      { key: 'Thu', label: 'T5' }, { key: 'Fri', label: 'T6' }, { key: 'Sat', label: 'T7' }, { key: 'Sun', label: 'CN' }
  ];

  // --- HÀM XỬ LÝ NHIỆM VỤ ĐƠN ---
  const handleAddSingleTask = (e) => {
    e.preventDefault();
    if (!newTask.title || !newTask.assigneeId || !newTask.endTime) return alert("Vui lòng điền đủ thông tin!");
    
    const staff = staffList.find(s => s.id === newTask.assigneeId);
    addTask({ 
        ...newTask, 
        assigneeName: staff ? staff.name : 'Unknown',
        deadline: newTask.endTime,
        paymentType: 'Standard', // Default
        disciplineName: 'None'   // Default
    });
    setNewTask({ title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST' });
    alert("Đã giao việc thành công!");
  };

  // --- HÀM XỬ LÝ LỊCH CÔNG TÁC ---
  const handleDayToggle = (dayKey) => {
      const currentDays = scheduleConfig.days;
      if (currentDays.includes(dayKey)) {
          setScheduleConfig({ ...scheduleConfig, days: currentDays.filter(d => d !== dayKey) });
      } else {
          setScheduleConfig({ ...scheduleConfig, days: [...currentDays, dayKey] });
      }
  };

  const handleSaveSchedule = (e) => {
      e.preventDefault();
      if (!scheduleConfig.title || !scheduleConfig.assigneeId || scheduleConfig.days.length === 0) {
          return alert("Vui lòng nhập tiêu đề, người nhận và chọn ít nhất 1 ngày!");
      }
      
      const staff = staffList.find(s => s.id === scheduleConfig.assigneeId);
      addSchedule({
          ...scheduleConfig,
          assigneeName: staff ? staff.name : 'Unknown'
      });
      
      setScheduleConfig({
          title: '', assigneeId: '', description: '',
          startTimeStr: '', endTimeStr: '', 
          assignedRole: 'ST', repeatWeeks: 1, days: []
      });
      alert("Đã lưu lịch công tác!");
  };

  const handleDeleteSchedule = (id) => {
      if(window.confirm("Xóa lịch trình này?")) deleteSchedule(id);
  };

  return (
    <div style={{ paddingBottom: '20px' }}>
      <h2 style={{ color: '#003366' }}>Quản lý Nhiệm vụ (Scheduler)</h2>

      <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px'}}>
          {/* CỘT TRÁI: GIAO VIỆC ĐƠN */}
          <div style={{ background: 'white', padding: '20px', borderRadius: '16px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)' }}>
            <h4 style={{ margin: '0 0 15px 0', color: '#003366' }}>1. Giao nhiệm vụ đơn</h4>
            <form onSubmit={handleAddSingleTask} style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              <input value={newTask.title} onChange={e => setNewTask({...newTask, title: e.target.value})} placeholder="Tiêu đề" style={styles.input} required />
              <select value={newTask.assigneeId} onChange={e => setNewTask({...newTask, assigneeId: e.target.value})} style={styles.select} required>
                  <option value="">-- Chọn nhân sự --</option>
                  {staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}
              </select>
              <select value={newTask.assignedRole} onChange={e => setNewTask({...newTask, assignedRole: e.target.value})} style={styles.select}>
                  {['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}
              </select>
              <div style={{display: 'flex', gap: '5px'}}>
                  <div style={{flex:1}}>
                      <label style={styles.label}>Bắt đầu</label>
                      <input type="datetime-local" value={newTask.startTime} onChange={e => setNewTask({...newTask, startTime: e.target.value})} style={styles.input} required />
                  </div>
                  <div style={{flex:1}}>
                      <label style={styles.label}>Kết thúc</label>
                      <input type="datetime-local" value={newTask.endTime} onChange={e => setNewTask({...newTask, endTime: e.target.value})} style={styles.input} required />
                  </div>
              </div>
              <textarea value={newTask.description} onChange={e => setNewTask({...newTask, description: e.target.value})} placeholder="Mô tả..." style={{...styles.input, height: '60px'}} />
              <button type="submit" style={styles.btnSubmit}>Giao việc</button>
            </form>
          </div>

          {/* CỘT PHẢI: LÊN LỊCH CÔNG TÁC */}
          <div style={{ background: '#f0f9ff', padding: '20px', borderRadius: '16px', border: '1px solid #bae6fd' }}>
            <h4 style={{ margin: '0 0 15px 0', color: '#0284c7' }}>2. Lên lịch công tác (Lặp lại)</h4>
            <form onSubmit={handleSaveSchedule} style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                <input value={scheduleConfig.title} onChange={e => setScheduleConfig({...scheduleConfig, title: e.target.value})} placeholder="Tiêu đề lịch" style={styles.input} required />
                <select value={scheduleConfig.assigneeId} onChange={e => setScheduleConfig({...scheduleConfig, assigneeId: e.target.value})} style={styles.select} required>
                    <option value="">-- Chọn nhân sự --</option>
                    {staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
                
                <div style={{display: 'flex', gap: '10px', alignItems: 'center'}}>
                    <span style={styles.label}>Lặp lại mỗi:</span>
                    <input type="number" min="1" value={scheduleConfig.repeatWeeks} onChange={e => setScheduleConfig({...scheduleConfig, repeatWeeks: Number(e.target.value)})} style={{...styles.input, width: '60px'}} />
                    <span style={styles.label}>tuần</span>
                </div>

                <div>
                    <label style={styles.label}>Chọn ngày trong tuần:</label>
                    <div style={{display: 'flex', gap: '5px', marginTop: '5px', flexWrap:'wrap'}}>
                        {daysOfWeek.map(day => (
                            <button 
                                key={day.key} 
                                type="button"
                                onClick={() => handleDayToggle(day.key)}
                                style={{
                                    padding: '5px 8px', borderRadius: '4px', border: '1px solid #ccc', cursor: 'pointer',
                                    background: scheduleConfig.days.includes(day.key) ? '#0284c7' : 'white',
                                    color: scheduleConfig.days.includes(day.key) ? 'white' : 'black'
                                }}
                            >
                                {day.label}
                            </button>
                        ))}
                    </div>
                </div>

                <div style={{display: 'flex', gap: '5px'}}>
                    <div style={{flex:1}}>
                        <label style={styles.label}>Giờ bắt đầu</label>
                        <input type="time" value={scheduleConfig.startTimeStr} onChange={e => setScheduleConfig({...scheduleConfig, startTimeStr: e.target.value})} style={styles.input} required />
                    </div>
                    <div style={{flex:1}}>
                        <label style={styles.label}>Giờ kết thúc</label>
                        <input type="time" value={scheduleConfig.endTimeStr} onChange={e => setScheduleConfig({...scheduleConfig, endTimeStr: e.target.value})} style={styles.input} required />
                    </div>
                </div>

                <button type="submit" style={{...styles.btnSubmit, background: '#0284c7'}}>Lưu lịch</button>
            </form>
          </div>
      </div>

      {/* DANH SÁCH LỊCH ĐÃ THIẾT LẬP */}
      <div style={{ marginTop: '20px', background: 'white', padding: '20px', borderRadius: '16px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
         <h4 style={{ color: '#003366', marginTop: 0 }}>3. Danh sách lịch đã thiết lập</h4>
         <table style={{ width: '100%', fontSize: '0.9rem', borderCollapse: 'collapse' }}>
            <thead>
                <tr style={{textAlign:'left', borderBottom: '1px solid #eee', background: '#f9fafb'}}>
                    <th style={{padding:'10px'}}>Tiêu đề</th>
                    <th style={{padding:'10px'}}>Nhân sự</th>
                    <th style={{padding:'10px'}}>Lặp lại</th>
                    <th style={{padding:'10px'}}>Ngày</th>
                    <th style={{padding:'10px'}}>Khung giờ</th>
                    <th style={{padding:'10px'}}>Hành động</th>
                </tr>
            </thead>
            <tbody>
                {schedules.map(sch => (
                    <tr key={sch.id} style={{ borderBottom: '1px solid #eee' }}>
                        <td style={{padding:'10px', fontWeight: 'bold'}}>{sch.title}</td>
                        <td style={{padding:'10px'}}>{sch.assigneeName}</td>
                        <td style={{padding:'10px'}}>{sch.repeatWeeks} tuần/lần</td>
                        <td style={{padding:'10px'}}>
                            {sch.days.map(d => <span key={d} style={{background:'#e0f2fe', padding:'2px 5px', borderRadius:'3px', marginRight:'3px', fontSize:'0.8rem'}}>{d}</span>)}
                        </td>
                        <td style={{padding:'10px'}}>{sch.startTimeStr} - {sch.endTimeStr}</td>
                        <td style={{padding:'10px'}}>
                            <button onClick={() => handleDeleteSchedule(sch.id)} style={{color:'red', border:'none', background:'none', cursor:'pointer', fontWeight: 'bold'}}>Xóa</button>
                        </td>
                    </tr>
                ))}
                {schedules.length === 0 && <tr><td colSpan="6" style={{padding:'20px', textAlign:'center', color:'#999'}}>Chưa có lịch nào được thiết lập.</td></tr>}
            </tbody>
         </table>
      </div>

      {/* DANH SÁCH NHIỆM VỤ ĐƠN */}
      <div style={{ marginTop: '20px', background: 'white', padding: '20px', borderRadius: '16px' }}>
         <h4>Danh sách nhiệm vụ đơn đang thực hiện</h4>
         <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
            <thead>
               <tr style={{textAlign:'left', borderBottom: '1px solid #eee'}}>
                 <th style={{padding:'10px'}}>Nhiệm vụ</th>
                 <th>Người làm</th>
                 <th>Hạn chót</th>
                 <th>Tiến độ</th>
                 <th>Hành động</th>
               </tr>
            </thead>
            <tbody>
               {tasks.map(t => (
                 <tr key={t.id} style={{ borderBottom: '1px solid #f9f9f9' }}>
                    <td style={{padding:'10px'}}><strong>{t.title}</strong></td>
                    <td>{t.assigneeName}</td>
                    <td>{new Date(t.endTime).toLocaleString()}</td>
                    <td>{t.progress}%</td>
                    <td><button onClick={()=>deleteTask(t.id)} style={{color:'red', border:'none', background:'none', cursor:'pointer'}}>Xóa</button></td>
                 </tr>
               ))}
            </tbody>
         </table>
      </div>
    </div>
  );
};

const styles = {
    input: { width: '100%', padding: '8px', borderRadius: '6px', border: '1px solid #ccc', boxSizing: 'border-box' },
    select: { width: '100%', padding: '8px', borderRadius: '6px', border: '1px solid #ccc', background: 'white' },
    label: { fontSize: '0.8rem', fontWeight: 'bold', color: '#555', marginBottom: '3px', display: 'block' },
    btnSubmit: { padding: '10px', background: '#003366', color: 'white', border: 'none', borderRadius: '6px', fontWeight: 'bold', cursor: 'pointer', marginTop: '5px' }
};

export default SchedulerTaskManager;
